rule.example:
class Bad {
    fun convert(i: Int): String {
        return "" + i  // violation: use string template instead
    }
}

class Good {
    fun convert(i: Int): String {
        return "$i"       // ok: idiomatic Kotlin string template
    }

    fun convert2(i: Int): String {
        return i.toString()  // ok: explicit conversion
    }
}

