rule.example:
class Bad {
    fun bad(): String {
        val sb = StringBuilder()
        sb.append("x")    // violation: use append('x')
        sb.append(",")    // violation: use append(',')
        return sb.toString()
    }
}

class Good {
    fun good(): String {
        val sb = StringBuilder()
        sb.append('x')      // ok: Char literal
        sb.append(',')      // ok: Char literal
        sb.append("hello")  // ok: multi-character string
        return sb.toString()
    }
}

