rule.example:
class Bad {
    fun copy(src: IntArray, dst: IntArray) {
        for (i in src.indices) {
            dst[i] = src[i]   // violation: use src.copyInto(dst)
        }
    }
}

class Good {
    fun copy(src: IntArray, dst: IntArray) {
        src.copyInto(dst)     // ok: built-in efficient copy
    }
    fun copyPartial(src: IntArray): IntArray {
        return src.copyOf()   // ok: returns a new copy
    }
}

import java.util.Calendar
import java.time.LocalDateTime

class Bad {
    fun currentMillis(): Long {
        return Calendar.getInstance().timeInMillis  // violation
    }
}

class Good {
    fun currentMillis(): Long {
        return System.currentTimeMillis()  // ok: no Calendar created
    }

    fun now(): LocalDateTime {
        return LocalDateTime.now()  // ok: java.time API
    }
}

class Bad {
    fun afterBulkLoad() {
        System.gc()                     // violation: unpredictable, may degrade throughput
        Runtime.getRuntime().gc()       // violation: same issue
    }
}

class Good {
    fun afterBulkLoad() {
        // ok: trust the JVM garbage collector; add metrics/monitoring instead
    }
}

import java.io.File
import java.io.FileInputStream
import java.nio.file.Files

class Bad {
    fun read(file: File): ByteArray {
        return FileInputStream(file).readBytes() // violation: use finalizer-free alternative
    }
}

class Good {
    fun read(file: File): ByteArray {
        return file.inputStream().use { it.readBytes() } // ok: extension function, no finalizer
    }

    fun readNio(file: File): ByteArray {
        return Files.newInputStream(file.toPath()).use { it.readBytes() } // ok: NIO approach
    }
}

property.value:
//PropertyDeclaration[
    pmd-kotlin:insideLoop()
    and Expression//PostfixUnaryExpression[
        pmd-kotlin:matchesSig('_#<init>(*)')
        and not(ancestor::FunctionDeclaration[ancestor::PropertyDeclaration])
        and (
            let $loopVars    := (
                    ancestor::ForStatement/VariableDeclaration
                    | ancestor::ForStatement/MultiVariableDeclaration/VariableDeclaration
                )/@Identifier,
                $derivedVars := ancestor::ForStatement//PropertyDeclaration[
                    not(ancestor::FunctionDeclaration[ancestor::PropertyDeclaration])
                    and Expression//PrimaryExpression[@Identifier = $loopVars]
                ]/VariableDeclaration/@Identifier
            return (
                empty($loopVars)
                or not(.//ValueArguments//PrimaryExpression[@Identifier = ($loopVars, $derivedVars)])
            )
        )
    ]
]

rule.example:
class Bad {
    fun process(items: List<String>): List<String> {
        val result = mutableListOf<String>()
        for (item in items) {
            val sb = StringBuilder()   // violation: new StringBuilder per iteration
            sb.append(item)
            result.add(sb.toString())
        }
        return result
    }
}

class Good {
    fun process(items: List<String>): List<String> {
        val result = mutableListOf<String>()
        val sb = StringBuilder()       // ok: single instance, cleared per iteration
        for (item in items) {
            sb.setLength(0)
            sb.append(item)
            result.add(sb.toString())
        }
        return result
    }
}

import java.math.BigInteger

class Bad {
    fun calc(): BigInteger {
        val zero = BigInteger.valueOf(0)   // violation: use BigInteger.ZERO
        val one  = BigInteger.valueOf(1L)  // violation: use BigInteger.ONE
        val ten  = BigInteger.valueOf(10)  // violation: use BigInteger.TEN
        return zero.add(one).add(ten)
    }
}

class Good {
    fun calc(): BigInteger {
        val zero = BigInteger.ZERO          // ok: cached constant
        val one  = BigInteger.ONE           // ok: cached constant
        val ten  = BigInteger.TEN           // ok: cached constant
        val two  = BigInteger.valueOf(2)    // ok: 2 has no named constant
        val twoAlt = 2.toBigInteger()       // ok: idiomatic Kotlin extension
        return zero.add(one).add(ten).add(two)
    }
}

