rule.example:
class Bad {
    fun build(): String {
        val sb = StringBuilder()
        sb.append("hello").append(" world")  // violation: can be combined
        return sb.toString()
    }
}

class Good {
    fun build(): String {
        val sb = StringBuilder()
        sb.append("hello world")  // ok: single append
        return sb.toString()
    }

    fun buildTemplate(): String {
        return "hello world"  // better: use a string directly or string template
    }
}

class Bad {
    fun isBlankStr(s: String): Boolean {
        return s.trim().length == 0      // violation: allocates trimmed String
    }

    fun isBlankStr2(s: String): Boolean {
        return s.strip().isEmpty()       // violation: allocates stripped String
    }
}

class Good {
    fun isBlankStr(s: String): Boolean {
        return s.isBlank()               // ok: no allocation
    }

    fun isEmptyStr(s: String): Boolean {
        return s.isEmpty()               // ok: no trimming needed for pure empty check
    }
}

class Bad {
    fun buildMessage(prefix: String, value: Int): String {
        val sb = StringBuilder()
        sb.append(prefix + ": " + value)  // violation: intermediate String created
        return sb.toString()
    }
}

class GoodChain {
    fun buildMessage(prefix: String, value: Int): String {
        val sb = StringBuilder()
        sb.append(prefix).append(": ").append(value)  // ok: chained appends
        return sb.toString()
    }
}

class GoodBuildString {
    fun buildMessage(prefix: String, value: Int): String =
        buildString {                          // ok: Kotlin idiomatic builder
            append(prefix)
            append(": ")
            append(value)
        }
}

class Bad {
    fun bad(): String {
        return String("hello") // violation: unnecessary String constructor call
    }
}

class Good {
    fun good(): String {
        return "hello" // ok: use the string literal directly
    }
}

class Bad {
    fun bad(name: String): String {
        return name.toString() // violation: toString() on a String is a no-op
    }
}

class Good {
    fun good(name: String): String {
        return name // ok: use the String variable directly
    }
}

// violation: condition-only when with 2 branches -- use if/else instead
fun describeSmall(x: Int): String {
    return when {
        x == 0 -> "zero"
        else   -> "non-zero"
    }
}

// ok: condition-only when with 3 branches justifies using when
fun describeSign(x: Int): String {
    return when {
        x < 0  -> "negative"
        x == 0 -> "zero"
        else   -> "positive"
    }
}

// ok: typed subject -- idiomatic exhaustive matching on sealed/enum, always allowed
fun describe(type: AppType): String {
    return when (type) {
        AppType.GAME -> "game"
        else         -> "other"
    }
}

