rule.example:
class Bad {
    fun parseHeader(line: String): Int {
        return line.indexOf(":")    // violation: use indexOf(':')
    }

    fun findLast(path: String): Int {
        return path.lastIndexOf("/")  // violation: use lastIndexOf('/')
    }
}

class Good {
    fun parseHeader(line: String): Int {
        return line.indexOf(':')    // ok: Char overload, faster
    }

    fun findLast(path: String): Int {
        return path.lastIndexOf('/')  // ok: Char overload, faster
    }

    fun multiChar(s: String): Int {
        return s.indexOf("ab")  // ok: multi-character search, no Char alternative
    }
}

class Bad {
    fun convert(i: Int): String {
        return String.valueOf(i)  // violation
    }
}

class Good {
    fun convert(i: Int): String {
        return "$i"        // ok: idiomatic Kotlin string template
    }

    fun convert2(i: Int): String {
        return i.toString()  // ok: explicit toString()
    }
}

