rule.example:
class Bad {
    fun join(items: List<String>): String {
        var result = ""
        for (item in items) {
            result += item       // violation: creates a new StringBuilder per iteration
        }
        return result
    }
}

class Good {
    fun join(items: List<String>): String {
        val sb = StringBuilder()
        for (item in items) {
            sb.append(item)      // ok: single StringBuilder, append per iteration
        }
        return sb.toString()
    }

    fun joinKotlin(items: List<String>): String {
        return items.joinToString("")  // ok: idiomatic Kotlin
    }
}

class Bad {
    fun isLong(sb: StringBuilder): Boolean {
        return sb.toString().length > 100  // violation: allocates temporary String
    }
}

class Good {
    fun isLong(sb: StringBuilder): Boolean {
        return sb.length > 100  // ok: direct length property, no allocation
    }
}
